import requests
from requests.exceptions import RequestException
base='http://localhost:5003'
paths=['/','/login','/logout','/users','/user','/api','/api/','/api/users','/api/login','/admin','/dashboard','/home','/profile','/me','/flag','/secret','/download','/files','/file','/view','/health','/healthz','/status','/debug','/debug/vars','/docs','/swagger','/openapi.json','/static','/static/','/static/style.css','/assets','/config','/config.json','/ping','/check','/note','/notes','/message','/messages','/report','/submit','/search','/upload','/image','/images','/avatar','/settings','/whoami','/private','/hidden']
res=[]
for p in paths:
    try:
        r=requests.get(base+p, allow_redirects=False, timeout=5)
        res.append((p, r.status_code, r.headers.get('Location'), r.headers.get('Content-Type')))
    except RequestException as e:
        res.append((p,'ERR',None,str(e)))
for item in res:
    print(item)

